import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),l={name:"審計報告庫/財務審計/6903_巨漢/20260502/F17_籌碼分佈與法人動態分析_投資研究員.md"};function i(n,a,_,s,h,d){return e(),o("div",null,[...a[0]||(a[0]=[r('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢近半年外資買賣超約持平（淨買超約 60 萬股），投信與自營商幾乎零進出。千張大戶佔比約 80-85%（主為原始股東），籌碼極度集中，無鬆動跡象。流動性極差（日成交 &lt;300 張），法人無法建立部位，股價缺乏專業買盤。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>B（持平）。籌碼集中於內部人，結構穩定無異常。利空：法人參與度極低（合計持股 &lt;8%），無投信鎖碼，股價欠缺專業買盤支撐。流動性不足導致買賣價差大，不適合大資金參與，股價易受少數交易操控。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><strong>法人動向</strong>：2026 年 1-4 月外資累計淨買超約 60 萬股（買超 3,400 萬 vs 賣超 3,340 萬），動能中性。投信近半年零進出，顯示公司不在投信研究範圍內。自營商零進出。三大法人合計持股約 5-8%，以 2023 年 IPO 新股而言法人參與度明顯偏低，暗示市場對該股的關注度不足。</li><li><strong>大戶持股</strong>：千張大戶（持股 &gt;1,000 張）約 30-40 人，合計持股約 80-85%。400 張以上中實戶約 50-60 人，合計持股約 90-92%。近半年無明顯變化，股權結構穩定。大戶持股高度集中在原始股東，無籌碼鬆動跡象。</li><li><strong>散戶動向</strong>：散戶（持股 &lt;10 張）約 1,500-2,000 人，持股佔比約 10-15%。IPO 後散戶人數穩定，無大量湧入或退出的異常訊號。融資餘額極低（&lt;1% 股本），無散戶槓桿風險。</li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>法人冷落的結構性問題</strong>：無投信鎖碼、外資興趣缺缺，股價完全由內部人定價。缺乏法人研究覆蓋的公司，股價效率通常較低——好消息不會立即反映在股價上，壞消息也不會。資訊不對稱風險高，外部投資人處於劣勢地位。</li><li><strong>流動性陷阱與交易成本壓力</strong>：日均交易量僅 100-300 張，以股價 150 元計算日成交金額僅 1,500-4,500 萬。大額投資者若要建立 1,000 張部位需要 3-10 個交易日，過程可能推高成本。出脫時賣壓同樣巨大，形成隱含交易成本，對大資金不利。</li><li><strong>籌碼穩定的雙面刃利空</strong>：大戶持股穩定代表短線賣壓小，但也代表股價缺乏上漲催化劑——根本沒有人去「炒」這支股票。只有當公司宣布重大利多（如大訂單、高配息）吸引法人進場時，股價才可能出現結構性上漲。在此之前，股價將隨機遊走，上漲動能不足。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><p>FinMind：TaiwanStockInstitutionalHoldings（2026 年 1-4 月）</p>',12)])])}const u=t(l,[["render",i]]);export{p as __pageData,u as default};
